// 気象庁API レスポンスを解析して悪天候を検出
const data = $input.first().json;

// 最初の予報エリア（千葉県北西部 = 成田エリア）
const area = data[0];
const timeSeries = area?.timeSeries ?? [];

// 天気コード系列を取得（0番目: 天気・風・波）
const weatherSeries = timeSeries[0];
const areas = weatherSeries?.areas ?? [];

// 千葉県北西部（area.area.code = 130010）または最初のエリア
const targetArea = areas.find(a => a.area?.code === '130010') ?? areas[0];
const weatherCodes = targetArea?.weatherCodes ?? [];
const weathers = targetArea?.weathers ?? [];
const winds = targetArea?.winds ?? [];

// 降水確率系列
const rainSeries = timeSeries[1];
const rainAreas = rainSeries?.areas ?? [];
const rainArea = rainAreas.find(a => a.area?.code === '130010') ?? rainAreas[0];
const pops = rainArea?.pops ?? [];

// 悪天候判定
const SEVERE_CODES = ['300','302','303','308','309','313','314','315','316','317','320','321','323','324','325','326','327','328','329','340','350','361','371','400','401','402','403','405','406','407','409','411','413','414','420','421','422','423','424','425','426','427','450'];
const TYPHOON_WORDS = ['台風','暴風','大雨','暴雨','特別警報'];
const RAIN_THRESHOLD = 70;

const hasSevereCode = weatherCodes.slice(0, 4).some(c => SEVERE_CODES.includes(c));
const hasTyphoonWord = weathers.slice(0, 4).some(w => TYPHOON_WORDS.some(t => w.includes(t)));
const hasHeavyRain = pops.slice(0, 4).some(p => parseInt(p) >= RAIN_THRESHOLD);
const hasHighWind = winds.slice(0, 4).some(w => w.includes('非常に強') || w.includes('暴風'));

const isSevere = hasSevereCode || hasTyphoonWord || hasHeavyRain || hasHighWind;

if (!isSevere) {
  return [{ json: { skip: true, reason: '通常天気' } }];
}

// アラートメッセージ生成
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
const dateStr = tomorrow.toLocaleDateString('ja-JP', { timeZone: 'Asia/Tokyo', month: 'long', day: 'numeric', weekday: 'short' });

const weatherDesc = weathers[0] ?? '悪天候';
const maxPop = Math.max(...pops.slice(0, 4).map(p => parseInt(p) || 0));
const windDesc = winds[0] ?? '';

const reasons = [];
if (hasTyphoonWord) reasons.push('🌀 台風・暴風警報');
if (hasHeavyRain) reasons.push(`🌧 降水確率 ${maxPop}%`);
if (hasHighWind) reasons.push(`💨 暴風: ${windDesc}`);
if (hasSevereCode && !hasTyphoonWord && !hasHeavyRain) reasons.push('⛈ 荒天コード検知');

const msg = [
  `⚠️ <b>KAIROX 悪天候アラート</b>`,
  `📅 対象: ${dateStr}`,
  ``,
  `🔴 検知内容:`,
  ...reasons.map(r => `  ${r}`),
  ``,
  `📋 予報: ${weatherDesc}`,
  ``,
  `🚨 アクション確認:`,
  `  ・受付制限 or 配達時間延長を検討`,
  `  ・顧客へ遅延可能性を事前通知`,
  `  ・ドライバー安全確認`,
].join('\n');

return [{ json: { skip: false, message: msg } }];
